import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;

public class SecurePathTraversalExample {

    public static void main(String[] args) {
        String baseDir = "/path/to/secure/directory"; // Base directory to restrict file access
        String userInput = "input.txt"; // User-supplied file input

        try {
            File file = new File(baseDir, userInput).getCanonicalFile();

            if (!file.toPath().startsWith(new File(baseDir).toPath())) {
                System.out.println("Access denied. Invalid file path.");
                return;
            }

            FileInputStream fis = new FileInputStream(file);

            int content;
            while ((content = fis.read()) != -1) {
                System.out.print((char) content);
            }

            fis.close();
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }
}
